import React from 'react';
import styled from 'styled-components';
import { StaticQuery, graphql } from 'gatsby';
import Img from 'gatsby-image';

import { Container } from '@components/global';
import ExternalLink from '@common/ExternalLink';

import MailIcon from '@static/icons/mail.svg';
import TwitterIcon from '@static/icons/twitter.svg';
import MediumIcon from '@static/icons/medium.svg';
import LinkedinIcon from '@static/icons/linkedin.svg'
import InstagramIcon from '@static/icons/instagram.svg';

const SOCIAL = [
  {
    icon: MailIcon,
    link: 'mailto:gustavo@padovan.org',
  },
  {
    icon: TwitterIcon,
    link: 'https://twitter.com/guspadovan',
  },
  {
    icon: MediumIcon,
    link: 'https://medium.com/gusp',
  },
  {
    icon: LinkedinIcon,
    link: 'https://www.linkedin.com/in/gustavo-padovan/',
  },
  {
    icon: InstagramIcon,
    link: 'https://instagram.com/guspadovan',
  },
];

const Header = () => (
  <StaticQuery
    query={graphql`
      query {
        art_build: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "gustavo-padovan" }
        ) {
          childImageSharp {
            fluid(maxWidth: 800) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
      }
    `}
    render={data => (
      <HeaderWrapper>
        <Container>
          <Grid>
            <Art>
              <Img
                fluid={data.art_build.childImageSharp.fluid}
                style={{ borderRadius: '50%' }}
              />
            </Art>
            <Text>
              <h1>
                Hi, I am
                <br />
                Gustavo Padovan
              </h1>
              <br />
                  <React.Fragment>
                    <FooterWrapper>
                      <StyledContainer>
                        <SocialIcons>
                          {SOCIAL.map(({ icon, link }) => (
                            <ExternalLink href={link}>
                              <img src={icon} alt="link" />
                            </ExternalLink>
                          ))}
                        </SocialIcons>
                      </StyledContainer>
                    </FooterWrapper>
                  </React.Fragment>
            </Text>
          </Grid>
        </Container>
      </HeaderWrapper>
    )}
  />
);

const HeaderWrapper = styled.header`
  background-color: ${props => props.theme.color.primary};
  padding-top: 96px;

  @media (max-width: ${props => props.theme.screen.md}) {
    padding-top: 128px;
  }
`;

const Art = styled.figure`
  width: 100%;
  margin: 0;

  > div {

    @media (max-width: ${props => props.theme.screen.md}) {
      width: 100%;
    }
  }
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center;
  grid-gap: 64px;

  @media (max-width: ${props => props.theme.screen.md}) {
    grid-template-columns: 1fr;
    grid-gap: 80px;

    > ${Art} {
      order: 2;
    }
  }
`;

const Text = styled.div`
  justify-self: center;

  @media (max-width: ${props => props.theme.screen.md}) {
    justify-self: start;
  }
`;

const StyledExternalLink = styled(ExternalLink)`
  color: inherit;
  text-decoration: none;

  &:hover {
    color: ${props => props.theme.color.black.regular};
  }
`;

const SocialIcons = styled.div`
  display: flex;

  img {
    margin: 0 8px;
    width: 24px;
    height: 24px;
  }

  @media (max-width: ${props => props.theme.screen.sm}) {
    margin-top: 40px;
  }
`;

const FooterWrapper = styled.footer`
  background-color: ${props => props.theme.color.primary};
  padding: 32px 0;
`;

const StyledContainer = styled(Container)`
  display: flex;
  justify-content: space-between;
  align-items: center;

  @media (max-width: ${props => props.theme.screen.sm}) {
    flex-direction: column;
    text-align: center;
  }
`;

export default Header;
