import React from 'react';
import styled from 'styled-components';
import { StaticQuery, graphql } from 'gatsby';
import Img from 'gatsby-image';

import { Section, Container } from '@components/global';
import ExternalLink from '@common/ExternalLink';

const About = () => (
  <StaticQuery
    query={graphql`
      query {
        collabora: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "collabora" }
        ) {
          childImageSharp {
            fluid(maxWidth: 800) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
        linuxdevbr: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "linuxdev-br" }
        ) {
          childImageSharp {
            fluid(maxWidth: 800) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
        tux: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "tux" }
        ) {
          childImageSharp {
            fluid(maxHeight: 400) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
        mooks: file(
          sourceInstanceName: { eq: "art" }
          name: { eq: "gpsl-mooks" }
        ) {
          childImageSharp {
            fluid(maxWidth: 800) {
              ...GatsbyImageSharpFluid_withWebp_tracedSVG
            }
          }
        }
      }
    `}
    render={data => (
      <Section id="about">
        <Container>
          <Grid>
            <div>
              <p>
              I am Linux Core Technologies Lead, Client Relationship Manager and
              Partner at <ExternalLink href="https://www.collabora.com/">Collabora
              </ExternalLink>, a  well respected Open Source Software
              consultancy that helps top companies in the world to create
              the next generation of technology with Open Source Software inside. 
              Along with Sjoerd Simons we lead the Core team inside Collabora,
              that supports clients on hardware enablement, kernel development,
              base platform and generic userspace needs. I also co- manage the
              relationship with one the best Collabora clients. Collabora's
              mission is to accelerate the adoption of Open Source throughout
              the industry.
              
              </p>
            </div>
            <Art>
              <ExternalLink href="https://www.collabora.com/">
                <Img fluid={data.collabora.childImageSharp.fluid} />
              </ExternalLink>
            </Art>
          </Grid>
          <br />
          <Grid inverse>
            <Art>
              <ExternalLink href="https://linuxdev-br.net">
                <Img fluid={data.linuxdevbr.childImageSharp.fluid} />
              </ExternalLink>
            </Art>
            <div>
              <p>
                 After many years traveling around the globe attending and
                 speaking at Open Source and Linux conferences I felt we did
                 not have any forum in Brazil to talk about upstream
                 development of technologies from the Linux world.In 2017 I invited
                 two of my best friends, Bruno Dilly and João Moreira, and together
                 we co-founded the <ExternalLink href="https://linuxdev-br.net">
                   Linux Developer Conference Brazil</ExternalLink> - linuxdev-br. 
                 A conference born to be international and act as a meeting point 
                 for Brazilian and international community. 
                 See our <ExternalLink href="https://linuxdev-br.net/mission">mission</ExternalLink>.
                
              </p>
            </div>
          </Grid>
          <Grid>
            <div>
              <p>
              I spent a decade as developer and maintainer in the Linux Kernel community.
              During that time I worked in the Bluetooth subsystem as developer and co-maintainer.
              Later I moved on the graphics and media area, where I developed for drm and media
              subsystem where I help with development of the Atomic Modesetting API and added suppor
              to Explicit Synchronization to mainline Linux Kernel helping unifying the Android and
              Linux generic stacks.
              </p>
            </div>
            <Art>
              <ExternalLink href="https://www.kernel.org/">
                <Img fluid={data.tux.childImageSharp.fluid} />
              </ExternalLink>
            </Art>
          </Grid>
          <Grid inverse>
            <Art>
                <Img fluid={data.mooks.childImageSharp.fluid} />
            </Art>
            <div>
              <p>
                During high-school, in 2004, I was also doing technical formation on programming
                I remember one day they announced a Linux workshop to be given by
                a FOSS group from the University of Campinas (Unicamp) in Brazil.
                That group was called GPSL (Grupo Pró Software Livre in Portuguese) and
                they teached us very basic things in GNU/Linux like the 'ls' command, it
                was my fisrt exposure ever to Free Software and its filosofy, It hooked me!
                2 years later I was a Computer Science freshemen at Unicamp and met GPSL again
                and quickly became one of the group's leader or "president" as my friends
                there - the same guys teached me about GNU/Linux that day at high-school. 
                The rest is history! The cute flying cow you see here was GPSL mascot. :)
              </p>
            </div>
          </Grid>
        </Container>
      </Section>
    )}
  />
);

const Grid = styled.div`
  display: grid;
  grid-template-columns: 3fr 2fr;
  grid-gap: 40px;
  text-align: right;
  align-items: center;
  justify-items: center;
  margin: 24px 0;

  ${props =>
    props.inverse &&
    `
    text-align: left;
    grid-template-columns: 2fr 3fr;
  `}

  h2 {
    margin-bottom: 16px;
  }

  @media (max-width: ${props => props.theme.screen.md}) {
    grid-template-columns: 1fr;
    text-align: left;
    margin-bottom: 96px;

    &:last-child {
      margin-bottom: 24px;
    }

    ${props =>
      props.inverse &&
      `
        ${Art} {
          order: 2;
        }
    `}
  }
`;

const Art = styled.figure`
  margin: 0;
  max-width: 380px;
  width: 100%;
`;

export default About;
